   227→func (s *TagScanner) getDeletedDirs(ctx context.Context, fsDirs dirMap, dbDirs map[string]struct{}) []string {
   228→	start := time.Now()
   229→	log.Trace(ctx, "Checking for deleted folders")
   230→	var deleted []string
   231→
   232→	for d := range dbDirs {
   233→		if _, ok := fsDirs[d]; !ok {
