   243→func (s *TagScanner) processDeletedDir(ctx context.Context, refresher *refresher, dir string) error {
   244→	start := time.Now()
   245→
   246→	mfs, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
   247→	if err != nil {
   248→		return err
   249→	}
   250→
   251→	c, err := s.ds.MediaFile(ctx).DeleteByPath(dir)
   252→	if err != nil {
   253→		return err
   254→	}
   255→	s.cnt.deleted += c
   256→
   257→	for _, t := range mfs {
   258→		refresher.accumulate(t)
   259→	}
   260→
   261→	err = refresher.flush(ctx)
   262→	log.Info(ctx, "Finished processing deleted folder", "dir", dir, "purged", len(mfs), "elapsed", time.Since(start))
   263→	return err
   264→}
