   143→func (s MediaFileMapper) mapGenres(genres []string) (string, model.Genres) {
   144→	var result model.Genres
   145→	unique := map[string]struct{}{}
   146→	var all []string
   147→	for i := range genres {
   148→		gs := strings.FieldsFunc(genres[i], func(r rune) bool {
   149→			return strings.ContainsRune(conf.Server.Scanner.GenreSeparators, r)
   150→		})
   151→		for j := range gs {
   152→			g := strings.TrimSpace(gs[j])
   153→			key := strings.ToLower(g)
   154→			if _, ok := unique[key]; ok {
   155→				continue
   156→			}
   157→			all = append(all, g)
   158→			unique[key] = struct{}{}
   159→		}
   160→	}
   161→	for _, g := range all {
   162→		genre := model.Genre{Name: g}
   163→		_ = s.genres.Put(&genre)
   164→		result = append(result, genre)
   165→	}
   166→	if len(result) == 0 {
