   172→func (s MediaFileMapper) mapDates(md metadata.Tags) (year int, date string,
   173→	originalYear int, originalDate string,
   174→	releaseYear int, releaseDate string) {
   175→	// Start with defaults
   176→	year, date = md.Date()
   177→	originalYear, originalDate = md.OriginalDate()
   178→	releaseYear, releaseDate = md.ReleaseDate()
   179→
   180→	// MusicBrainz Picard writes the Release Date of an album to the Date tag, and leaves the Release Date tag empty
   181→	taggedLikePicard := (originalYear != 0) &&
   182→		(releaseYear == 0) &&
   183→		(year >= originalYear)
   184→	if taggedLikePicard {
   185→		return originalYear, originalDate, originalYear, originalDate, year, date
   186→	}
   187→	// when there's no Date, first fall back to Original Date, then to Release Date.
   188→	if year == 0 {
   189→		if originalYear > 0 {
   190→			year, date = originalYear, originalDate
   191→		} else {
   192→			year, date = releaseYear, releaseDate
