	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{}, // First scan
	}

	// Create scanner
	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)

	// Execute scan
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	// Assertions
	require.NoError(t, err, "scan should succeed")
	assert.Greater(t, changeCount, int64(0), "should detect at least one change")

	// Verify mediafiles were created
	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	assert.Greater(t, len(mediaFiles), 0, "should create at least one mediafile")

	// Verify mediafile properties
	if len(mediaFiles) > 0 {
