	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	// Assertions
	require.NoError(t, err, "scan should succeed")
	assert.Greater(t, changeCount, int64(0), "should detect at least one change")

	// Verify mediafiles were created
