	// Setup
	ds := &tests.MockDataStore{}
	ds.MockedMediaFile = tests.CreateMockMediaFileRepo()
	ds.MockedAlbum = tests.CreateMockAlbumRepo()
	ds.MockedArtist = tests.CreateMockArtistRepo()
	ds.MockedGenre = &tests.MockedGenreRepo{}

	mockPlaylists := &mockPlaylists{}
	mockCacheWarmer := &mockCacheWarmer{}

	fixtureDir := getFixturePath("artist/an-album")

	// First scan
	lib := model.Library{
		ID:         1,
		Path:       fixtureDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress := make(chan uint32, 100)
	firstChangeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	require.NoError(t, err)
	assert.Greater(t, firstChangeCount, int64(0), "first scan should detect changes")

	// Get the updated timestamp from first scan
	mediaFiles, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles), 0)

	// Update library's last scan time to just after the file modification time
	lib.LastScanAt = time.Now()

	// Second scan (incremental)
	scanner2 := NewTagScanner(ds, mockPlaylists, mockCacheWarmer)
	progress2 := make(chan uint32, 100)
	secondChangeCount, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	require.NoError(t, err)
	assert.Equal(t, int64(0), secondChangeCount, "incremental scan should find no changes when files unchanged")
}

